```rust
fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let valid_business = ["electronics", "grocery", "pharmacy", "restaurant"];
    let mut valid: Vec<(String, String)> = Vec::new();

    for i in 0..code.len() {
        let c = code[i].clone();
        let bl = businessLine[i].clone();
        let active = isActive[i];

        if c.is_empty() {
            continue;
        }

        let is_valid_code = c.chars().all(|ch| ch.is_alphanumeric() || ch == '_');
        if !is_valid_code {
            continue;
        }

        if !valid_business.contains(&bl) {
            continue;
        }

        if !active {
            continue;
        }

        valid.push((c, bl));
    }

    valid.sort_by(|a, b| {
        let order_a = valid_business.iter().position(|x| x == &a.1).unwrap();
        let order_b = valid_business.iter().position(|x| x == &b.1).unwrap();
        if order_a != order_b {
            order_a.cmp(&order_b)
        } else {
            a.0.cmp(&b.0)
        }
    });

    valid.iter().map(|x| x.0.clone()).collect()
}
```

