__data__.content:
```cpp
#include <vector>
#include <string>
#include <regex>
#include <algorithm>
#include <functional>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    vector<pair<string, string>> validCoupons;
    regex pattern("^[a-zA-Z0-9_]+$");
    vector<string> validBusiness = {"electronics", "grocery", "pharmacy", "restaurant"};

    for (int i = 0; i < code.size(); ++i) {
        string c = code[i];
        string bl = businessLine[i];
        bool active = isActive[i];

        if (c.empty()) continue;
        if (!regex_match(c, pattern)) continue;
        if (find(validBusiness.begin(), validBusiness.end(), bl) == validBusiness.end()) continue;
        if (!active) continue;

        validCoupons.push_back({c, bl});
    }

    sort(validCoupons.begin(), validCoupons.end(), [&](const pair<string, string>& a, const pair<string, string>& b) {
        int orderA = -1, orderB = -1;
        for (int i = 0; i < validBusiness.size(); ++i) {
            if (validBusiness[i] == a.second) orderA = i;
            if (validBusiness[i] == b.second) orderB = i;
        }
        if (orderA != orderB) return orderA < orderB;
        return a.first < b.first;
    });

    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.first);
    }
    return result;
}
